function greet(name) {
  return `Hello, ${name}!`;
}

function main() {
  const message = greet('Alice'); // greet pushed, then popped
  console.log(message);           // console.log pushed, then popped
}

main(); // main pushed onto the call stack

console.log('1 - start');          // runs immediately (call stack)

setTimeout(() => {
  console.log('3 - timeout');       // runs after call stack empties
}, 0);

console.log('2 - end');             // runs immediately (call stack)

// Output order: 1 - start, 2 - end, 3 - timeout
// setTimeout callback runs AFTER the current synchronous code, even with delay 0

// utils.js
export function formatDate(date) {
  return date.toLocaleDateString();
}

// app.js
import { formatDate } from './utils.js';

const today = formatDate(new Date());
document.getElementById('date').textContent = today;

// Fetch a list of users from a public API and display them
async function loadUsers() {
  const list = document.getElementById('user-list');
  list.innerHTML = '<li>Loading...</li>';

  try {
    const response = await fetch('https://jsonplaceholder.typicode.com/users');
    if (!response.ok) {
      throw new Error(`HTTP error: ${response.status}`);
    }
    const users = await response.json();

    list.innerHTML = users
      .map(user => `<li><strong>${user.name}</strong> — ${user.email}</li>`)
      .join('');
  } catch (error) {
    list.innerHTML = `<li>Error: ${error.message}</li>`;
  }
}

document.addEventListener('DOMContentLoaded', loadUsers);

document.addEventListener('DOMContentLoaded', () => {
  const form    = document.getElementById('login-form');
  const emailEl = document.getElementById('email');
  const passEl  = document.getElementById('password');
  const emailErr = document.getElementById('email-error');
  const passErr  = document.getElementById('password-error');
  const submitBtn = document.getElementById('submit-btn');

  function showError(el, message) {
    el.textContent = message;
    el.hidden = false;
  }

  function clearError(el) {
    el.textContent = '';
    el.hidden = true;
  }

  // Real-time validation while typing
  emailEl.addEventListener('input', () => {
    if (emailEl.validity.typeMismatch || !emailEl.value.includes('@')) {
      showError(emailErr, 'Please enter a valid email address.');
    } else {
      clearError(emailErr);
    }
  });

  passEl.addEventListener('input', () => {
    if (passEl.value.length < 8) {
      showError(passErr, 'Password must be at least 8 characters.');
    } else {
      clearError(passErr);
    }
  });

  form.addEventListener('submit', async (event) => {
    event.preventDefault(); // stop default browser form submission

    let valid = true;

    if (!emailEl.value || !emailEl.value.includes('@')) {
      showError(emailErr, 'Email is required.');
      valid = false;
    }
    if (passEl.value.length < 8) {
      showError(passErr, 'Password must be at least 8 characters.');
      valid = false;
    }

    if (!valid) return;

    // Disable button to prevent double submit
    submitBtn.disabled = true;
    submitBtn.textContent = 'Signing in...';

    try {
      const response = await fetch('/api/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          email: emailEl.value,
          password: passEl.value,
        }),
      });

      if (!response.ok) {
        const { message } = await response.json();
        showError(emailErr, message || 'Login failed. Please try again.');
        return;
      }

      window.location.href = '/dashboard';
    } catch {
      showError(emailErr, 'Network error. Check your connection.');
    } finally {
      submitBtn.disabled = false;
      submitBtn.textContent = 'Sign in';
    }
  });
});

// ❌ Sorting 1 million items synchronously on click — page freezes
button.addEventListener('click', () => {
  const result = bigArray.sort((a, b) => a - b); // blocks rendering
  renderResults(result);
});

// ✅ Offload to a Web Worker for heavy computation
const worker = new Worker('sort-worker.js');
button.addEventListener('click', () => {
  worker.postMessage(bigArray);
});
worker.onmessage = (event) => {
  renderResults(event.data); // called when the worker finishes
};

// ❌ Variables declared without var/let/const go on window
function setup() {
  count = 0; // implicit global — window.count = 0
}

// Third-party script or browser extension might also use window.count
// and silently overwrite yours, or vice versa.

// ✅ Always declare variables explicitly
function setup() {
  let count = 0; // local to the function
}

// ❌ fetch() is async — data is not available on the next line
let data;
fetch('/api/items').then(r => r.json()).then(json => { data = json; });
console.log(data); // undefined — the fetch hasn't completed yet

// ✅ Use async/await or chain inside .then()
async function loadData() {
  const response = await fetch('/api/items');
  const data = await response.json();
  console.log(data); // available here
}

// ❌ Alternating reads and writes cause repeated layout recalculation
elements.forEach(el => {
  const height = el.offsetHeight;         // read — forces layout
  el.style.height = (height + 10) + 'px'; // write — invalidates layout
});

// ✅ Read all first, then write all
const heights = elements.map(el => el.offsetHeight); // read phase
elements.forEach((el, i) => {
  el.style.height = (heights[i] + 10) + 'px';       // write phase
});

// Load the chart library only when the user opens the charts section
document.getElementById('show-charts').addEventListener('click', async () => {
  const { renderCharts } = await import('./charts.js'); // loads on demand
  renderCharts();
});

// ❌ Dangerous: direct innerHTML with user data enables XSS
const name = new URLSearchParams(location.search).get('name');
document.getElementById('welcome').innerHTML = `Hello, ${name}!`;
// URL: ?name=<img src=x onerror=alert(document.cookie)>
// This executes attacker-controlled JavaScript

// ✅ Use textContent for user-supplied text — no HTML parsing
document.getElementById('welcome').textContent = `Hello, ${name}!`;

// ✅ Or sanitize with a trusted library before using innerHTML
